import torch
import torch.nn as nn
import torch.nn.functional as F

LATENT_DIM = 64   # z dimension
ACTION_DIM = 4    # number of discrete actions (or continuous action size)
OBS_DIM = 128     # flattened observation size


class Encoder(nn.Module):
    """Maps observation o_t -> latent z_t."""
    def __init__(self):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(OBS_DIM, 256), nn.ReLU(),
            nn.Linear(256, LATENT_DIM * 2),  # mean + log_var for reparameterization
        )

    def forward(self, obs):
        out = self.net(obs)
        mean, log_var = out.chunk(2, dim=-1)
        # Reparameterization trick: z = mean + eps * std
        std = (0.5 * log_var).exp()
        eps = torch.randn_like(std)
        z = mean + eps * std
        return z, mean, log_var  # z for downstream, mean/log_var for KL loss


class TransitionModel(nn.Module):
    """Predicts z_{t+1} from (z_t, a_t). Core world model."""
    def __init__(self):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(LATENT_DIM + ACTION_DIM, 256), nn.ELU(),
            nn.Linear(256, 256), nn.ELU(),
            nn.Linear(256, LATENT_DIM * 2),  # mean + log_var for stochastic transition
        )

    def forward(self, z, a):
        """a should be one-hot encoded for discrete actions."""
        x = torch.cat([z, a], dim=-1)
        out = self.net(x)
        mean, log_var = out.chunk(2, dim=-1)
        std = (0.5 * log_var).exp().clamp(min=1e-4)
        eps = torch.randn_like(std)
        z_next = mean + eps * std  # stochastic prediction
        return z_next, mean, log_var


class RewardModel(nn.Module):
    """Predicts scalar reward from latent state."""
    def __init__(self):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(LATENT_DIM, 128), nn.ELU(),
            nn.Linear(128, 1),
        )

    def forward(self, z):
        return self.net(z).squeeze(-1)  # shape: (batch,)


class Decoder(nn.Module):
    """Reconstructs observation from latent (training only)."""
    def __init__(self):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(LATENT_DIM, 256), nn.ReLU(),
            nn.Linear(256, OBS_DIM),
        )

    def forward(self, z):
        return self.net(z)
